const response = $input.first().json.choices[0].message.content;
try {
  let script;
  try {
    script = JSON.parse(response);
  } catch {
    const m = response.match(/\{[\s\S]*\}/);
    script = m ? JSON.parse(m[0]) : {};
  }
  const data = $('Webhook - TikTok').first().json.body;
  return [{ json: {
    ...script,
    video_id: data.video_id,
    user_id: data.user_id,
    platform: 'tiktok',
    language: data.language || 'nb',
    aspect_ratio: '9:16'
  }}];
} catch(e) {
  throw new Error('Script parse feilet: ' + e.message);
}

const item = items[0].json;
// ALLTID nb-NO-PernilleNeural
const tts_voice = 'nb-NO-PernilleNeural';
return [{ json: { ...item, tts_voice } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const voice = 'nb-NO-PernilleNeural';

const scenes = item.scenes || [];
const rawText = scenes.map(s => s.narration || '').filter(Boolean).join('. ');
const text = rawText.replace(/[\"'\`$\\]/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 2000);

const dir = `/workspace/video_assets/${videoId}`;
const output = `${dir}/voiceover.mp3`;

try {
  execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });
  execSync(`edge-tts --voice "${voice}" --text "${text}" --write-media "${output}"`, {
    encoding: 'utf-8', timeout: 300000, shell: '/bin/bash'
  });
  return [{ json: { ...item, voiceover_path: output, voice } }];
} catch(err) {
  throw new Error('Voiceover feilet: ' + err.message);
}

const item = items[0].json;
const scenes = item.scenes || [];
return scenes.map((scene, i) => ({
  json: {
    video_id: item.video_id,
    query: (scene.search_keywords && scene.search_keywords[0]) || item.topic || 'nature',
    duration: scene.duration_seconds || 6,
    index: i
  }
}));

const data = $input.first().json.hits || [];
if (!data.length) return [{ json: { video_url: null } }];
const best = data[0];
const url = best.videos?.large?.url || best.videos?.medium?.url || best.videos?.small?.url;
return [{ json: { video_url: url, pixabay_id: best.id } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const index = item.index;
const duration = item.duration;

if (!item.video_url) {
  const dir = `/workspace/video_assets/${videoId}/clips`;
  execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });
  execSync(`ffmpeg -y -f lavfi -i color=c=black:s=1080x1920:r=30 -t ${duration} -c:v libx264 -preset fast ${dir}/scene_${index}.mp4`, {
    encoding: 'utf-8', timeout: 120000, shell: '/bin/bash'
  });
  return [{ json: { clip_path: `${dir}/scene_${index}.mp4`, fallback: true } }];
}

const dir = `/workspace/video_assets/${videoId}/clips`;
execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });

try {
  execSync(`ffmpeg -y -i "${item.video_url}" -t ${duration} -c:v libx264 -preset fast -an ${dir}/scene_${index}.mp4`, {
    encoding: 'utf-8', timeout: 300000, shell: '/bin/bash'
  });
  return [{ json: { clip_path: `${dir}/scene_${index}.mp4` } }];
} catch(err) {
  execSync(`ffmpeg -y -f lavfi -i color=c=black:s=1080x1920:r=30 -t ${duration} -c:v libx264 -preset fast ${dir}/scene_${index}.mp4`, {
    encoding: 'utf-8', timeout: 120000, shell: '/bin/bash'
  });
  return [{ json: { clip_path: `${dir}/scene_${index}.mp4`, fallback: true } }];
}

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}/clips`;

const files = execSync(`ls ${dir}/scene_*.mp4 2>/dev/null | sort -V`, { encoding: 'utf-8', shell: '/bin/bash' }).trim();
if (!files) throw new Error('Ingen scener funnet');

execSync(`echo "$files" | sed "s/^/file '/;s/$/'/" > ${dir}/filelist.txt && cd ${dir} && ffmpeg -y -f concat -safe 0 -i filelist.txt -c:v libx264 -preset fast -c:a aac ${dir}/concat.mp4`, {
  encoding: 'utf-8', timeout: 300000, shell: '/bin/bash'
});

return [{ json: { concat_path: `${dir}/concat.mp4` } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const userId = item.user_id;
const dir = `/workspace/video_assets/${videoId}`;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

try {
  execSync(`ffmpeg -y -i "${dir}/concat.mp4" -i "${dir}/voiceover.mp3" -c:v copy -c:a aac -shortest "${dir}/final.mp4"`, {
    encoding: 'utf-8', timeout: 300000, shell: '/bin/bash'
  });
} catch(err) {
  throw new Error('Merge feilet: ' + err.message);
}

const storagePath = `${userId}/${videoId}/final.mp4`;
try {
  execSync(`curl -sf -X POST "${supabaseUrl}/storage/v1/object/videos/${storagePath}" -H "Authorization: Bearer ${serviceKey}" -H "Content-Type: video/mp4" --data-binary @"${dir}/final.mp4"`, {
    encoding: 'utf-8', timeout: 600000, shell: '/bin/bash'
  });
} catch(err) {
  throw new Error('Upload feilet: ' + err.message);
}

return [{ json: { ...item, video_url: `${supabaseUrl}/storage/v1/object/public/videos/${storagePath}` } }];
